insert into public.exercises (id, name, muscle_group, equipment, target, secondary_muscles, instructions, gif_path) values
  ('db-0001', '3/4 sit-up', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '2gPfomN'),
  ('db-0002', '45° side bend', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Stand with your feet shoulder-width apart and your arms extended straight down by your sides.','Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee.','Pause for a moment at the bottom, then slowly return to the starting position.','Repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'Hy9D21L'),
  ('db-0003', 'air bike', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your hands placed behind your head.','Lift your legs off the ground and bend your knees at a 90-degree angle.','Bring your right elbow towards your left knee while simultaneously straightening your right leg.','Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg.','Continue alternating sides in a pedaling motion for the desired number of repetitions.']::text[], '1ZFqTDN'),
  ('db-1512', 'all fours squad stretch', 'Legs', 'Body Weight', 'quads', ARRAY['hamstrings','glutes']::text[], ARRAY['Start on all fours with your hands directly under your shoulders and your knees directly under your hips.','Extend one leg straight back, keeping your knee bent and your foot flexed.','Slowly lower your hips towards the ground, feeling a stretch in your quads.','Hold this position for 20-30 seconds.','Switch legs and repeat the stretch on the other side.']::text[], 'qBcKorM'),
  ('db-0006', 'alternate heel touchers', 'Core', 'Body Weight', 'abs', ARRAY['obliques']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Extend your arms straight out to the sides, parallel to the ground.','Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel.','Return to the starting position and repeat on the left side, reaching your left hand towards your left heel.','Continue alternating sides for the desired number of repetitions.']::text[], 'qaZVsGk'),
  ('db-0007', 'alternate lateral pulldown', 'Back', 'Cable', 'lats', ARRAY['biceps','rhomboids']::text[], ARRAY['Sit on the cable machine with your back straight and feet flat on the ground.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Lean back slightly and pull the handles towards your chest, squeezing your shoulder blades together.','Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.','Repeat for the desired number of repetitions.']::text[], '4IKbhHV'),
  ('db-1368', 'ankle circles', 'Legs', 'Body Weight', 'calves', ARRAY['ankle stabilizers']::text[], ARRAY['Sit on the ground with your legs extended in front of you.','Lift one leg off the ground and rotate your ankle in a circular motion.','Perform the desired number of circles in one direction, then switch to the other direction.','Repeat with the other leg.']::text[], 'uL9CsKm'),
  ('db-3293', 'archer pull up', 'Back', 'Body Weight', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.','Engage your core and pull your shoulder blades down and back.','As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight.','Continue pulling until your chin is above the bar and your bent arm is fully flexed.','Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side.','Alternate sides with each repetition.']::text[], '72BC5Za'),
  ('db-3294', 'archer push up', 'Chest', 'Body Weight', 'pectorals', ARRAY['triceps','shoulders','core']::text[], ARRAY['Start in a push-up position with your hands slightly wider than shoulder-width apart.','Extend one arm straight out to the side, parallel to the ground.','Lower your body by bending your elbows, keeping your back straight and core engaged.','Push back up to the starting position.','Repeat on the other side, extending the opposite arm out to the side.','Continue alternating sides for the desired number of repetitions.']::text[], 'A9qxk2F'),
  ('db-2355', 'arm slingers hanging bent knee legs', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','back']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle.','Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible.','Slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'uWpxD4v'),
  ('db-2333', 'arm slingers hanging straight legs', 'Core', 'Body Weight', 'abs', ARRAY['shoulders','back']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your legs straight down.','Engage your core and lift your legs up in front of you until they are parallel to the ground.','Hold for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PXTIwgu'),
  ('db-3214', 'arms apart circular toe touch (male)', 'Legs', 'Body Weight', 'glutes', ARRAY['hamstrings','quadriceps','calves']::text[], ARRAY['Stand with your feet shoulder-width apart and arms extended to the sides.','Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand.','As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance.','Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you.','Continue alternating sides for the desired number of repetitions.']::text[], 'RtyAsy1'),
  ('db-3204', 'arms overhead full sit-up (male)', 'Core', 'Body Weight', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Lie flat on your back with your knees bent and feet flat on the ground.','Extend your arms overhead, keeping them straight.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'NAkmgdx'),
  ('db-0009', 'assisted chest dip (kneeling)', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the machine to your desired height and secure your knees on the pad.','Grasp the handles with your palms facing down and your arms fully extended.','Lower your body by bending your elbows until your upper arms are parallel to the floor.','Pause for a moment, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'PAgTVaK'),
  ('db-0011', 'assisted hanging knee raise', 'Core', 'Assisted', 'abs', ARRAY['hip flexors']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core muscles and lift your knees towards your chest, bending at the hips and knees.','Pause for a moment at the top of the movement, squeezing your abs.','Slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '03lzqwk'),
  ('db-0010', 'assisted hanging knee raise with throw down', 'Core', 'Assisted', 'abs', ARRAY['hip flexors','lower back']::text[], ARRAY['Hang from a pull-up bar with your arms fully extended and your palms facing away from you.','Engage your core and lift your knees towards your chest, keeping your legs together.','Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully.','Allow your legs to swing back up and repeat the movement for the desired number of repetitions.']::text[], '8K0w2yA'),
  ('db-1708', 'assisted lying calves stretch', 'Legs', 'Assisted', 'calves', ARRAY['hamstrings']::text[], ARRAY['Lie on your back with your legs extended.','Bend one knee and place your foot flat on the ground.','Using your hands or a towel, gently pull your toes towards your body, feeling a stretch in your calf.','Hold the stretch for 20-30 seconds.','Release the stretch and repeat on the other leg.']::text[], 'GxDwDX0'),
  ('db-1709', 'assisted lying glutes stretch', 'Legs', 'Assisted', 'glutes', ARRAY['hamstrings']::text[], ARRAY['Lie on your back with your legs extended.','Bend your right knee and place your right ankle on your left thigh, just above the knee.','Grasp your left thigh with both hands and gently pull it towards your chest.','Hold the stretch for 20-30 seconds.','Release and repeat on the other side.']::text[], 'yn0LjwL'),
  ('db-1710', 'assisted lying gluteus and piriformis stretch', 'Legs', 'Assisted', 'glutes', ARRAY['hamstrings']::text[], ARRAY['Lie on your back with your legs extended.','Bend your right knee and place your right ankle on your left thigh, just above the knee.','Grasp your left thigh with both hands and gently pull it towards your chest.','Hold the stretch for 20-30 seconds.','Release the stretch and repeat on the other side.']::text[], 'RQNVT10'),
  ('db-0012', 'assisted lying leg raise with lateral throw down', 'Core', 'Assisted', 'abs', ARRAY['hip flexors','obliques']::text[], ARRAY['Lie flat on your back with your legs extended and your arms by your sides.','Place your hands under your glutes for support.','Engage your abs and lift your legs off the ground, keeping them straight.','While keeping your legs together, lower them to one side until they are a few inches above the ground.','Pause for a moment, then lift your legs back to the starting position.','Repeat the movement to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'UGhRD1A'),
  ('db-0013', 'assisted lying leg raise with throw down', 'Core', 'Assisted', 'abs', ARRAY['hip flexors','quadriceps']::text[], ARRAY['Lie flat on your back with your legs extended and your arms by your sides.','Place your hands under your glutes for support.','Engage your core and lift your legs off the ground, keeping them straight.','Raise your legs until they are perpendicular to the ground.','Lower your legs back down to the starting position.','Simultaneously, throw your legs down towards the ground, keeping them straight.','Raise your legs back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VX5YKR5'),
  ('db-0014', 'assisted motion russian twist', 'Core', 'Medicine Ball', 'abs', ARRAY['obliques','lower back']::text[], ARRAY['Sit on the ground with your knees bent and feet flat on the floor.','Hold the medicine ball with both hands in front of your chest.','Lean back slightly, engaging your abs and keeping your back straight.','Slowly twist your torso to the right, bringing the medicine ball towards the right side of your body.','Pause for a moment, then twist your torso to the left, bringing the medicine ball towards the left side of your body.','Continue alternating sides for the desired number of repetitions.']::text[], 'r7cT9YD'),
  ('db-0015', 'assisted parallel close grip pull-up', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the machine to your desired weight and height.','Place your hands on the parallel bars with a close grip, palms facing each other.','Hang from the bars with your arms fully extended and your feet off the ground.','Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your body.','Continue pulling until your chin is above the bars.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vrhHa6D'),
  ('db-0016', 'assisted prone hamstring', 'Legs', 'Assisted', 'hamstrings', ARRAY['glutes','lower back']::text[], ARRAY['Lie face down on a mat or bench with your legs fully extended.','Have a partner or use a resistance band to secure your ankles.','Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VedGSby'),
  ('db-1713', 'assisted prone lying quads stretch', 'Legs', 'Assisted', 'quads', ARRAY['hamstrings','glutes']::text[], ARRAY['Lie face down on the ground with your legs extended.','Bend your left knee and reach back with your left hand to grab your left foot or ankle.','Gently pull your left foot towards your glutes, feeling a stretch in your left quad.','Hold the stretch for 20-30 seconds, then release.','Repeat with your right leg.']::text[], 'YUYAMEj'),
  ('db-1714', 'assisted prone rectus femoris stretch', 'Core', 'Assisted', 'abs', ARRAY['quadriceps']::text[], ARRAY['Lie face down on the ground with your legs straight.','Bend your right knee and reach back with your right hand to grab your right foot or ankle.','Gently pull your right foot or ankle towards your glutes, feeling a stretch in the front of your right thigh.','Hold the stretch for 20-30 seconds.','Release and repeat on the other side.']::text[], '2Ryn564'),
  ('db-0017', 'assisted pull-up', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the machine to your desired weight and height settings.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Hang with your arms fully extended and your feet off the ground.','Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body.','Continue pulling until your chin is above the handles.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'kiJ4Z2K'),
  ('db-1716', 'assisted seated pectoralis major stretch with stability ball', 'Chest', 'Assisted', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Sit on a stability ball with your feet flat on the ground and your back straight.','Hold a stability ball with both hands and extend your arms straight out in front of you.','Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles.','Hold the stretch for a few seconds, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'RoV1Rfa'),
  ('db-1712', 'assisted side lying adductor stretch', 'Legs', 'Assisted', 'adductors', ARRAY['hamstrings','glutes']::text[], ARRAY['Lie on your side with your legs straight and stacked on top of each other.','Bend your bottom leg slightly for stability.','Place your top foot on a stable surface, such as a bench or step.','Keeping your top leg straight, slowly lower it towards the ground, feeling a stretch in your inner thigh.','Hold the stretch for 20-30 seconds.','Return to the starting position and repeat on the other side.']::text[], 'hC6oYY5'),
  ('db-1758', 'assisted sit-up', 'Core', 'Assisted', 'abs', ARRAY['hip flexors']::text[], ARRAY['Sit on the edge of a bench or have someone hold your feet down.','Lie flat on your back with your knees bent and feet flat on the ground.','Place your hands behind your head with your elbows pointing outwards.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'aumB2IV'),
  ('db-1431', 'assisted standing chin-up', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the machine to your desired assistance level.','Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart.','Keep your chest up and shoulders back, engage your core, and slightly bend your knees.','Pull your body up by flexing your elbows and driving your elbows down towards your sides.','Continue pulling until your chin is above the bar.','Pause for a moment at the top, then slowly lower your body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '7OeHptV'),
  ('db-1432', 'assisted standing pull-up', 'Back', 'Leverage Machine', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Adjust the machine to your desired weight and height settings.','Stand facing the machine with your feet shoulder-width apart.','Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.','Engage your lats and biceps, and pull yourself up towards the handles.','Pause for a moment at the top, squeezing your back muscles.','Slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'f4xtKBj'),
  ('db-0018', 'assisted standing triceps extension (with towel)', 'Arms', 'Assisted', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold a towel with both hands behind your head.','Keep your elbows close to your ears and your upper arms stationary.','Slowly extend your forearms upward, squeezing your triceps at the top.','Pause for a moment, then slowly lower the towel back down to the starting position.','Repeat for the desired number of repetitions.']::text[], '7HcfMBP'),
  ('db-0019', 'assisted triceps dip (kneeling)', 'Arms', 'Leverage Machine', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Adjust the machine to your desired weight and height.','Kneel down on the pad facing the machine, with your hands gripping the handles.','Lower your body by bending your elbows, keeping your back straight and close to the machine.','Pause for a moment at the bottom, then push yourself back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'J60bN17'),
  ('db-2364', 'assisted wide-grip chest dip (kneeling)', 'Chest', 'Leverage Machine', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Adjust the machine to your desired height and secure your knees on the pad.','Grasp the handles with a wide grip and keep your elbows slightly bent.','Lower your body by bending your elbows until your upper arms are parallel to the floor.','Push yourself back up to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], 'PnZJIrk'),
  ('db-3220', 'astride jumps (male)', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Bend your knees and lower your body into a squat position.','Jump explosively upwards, extending your legs and arms.','While in the air, spread your legs apart and bring your arms out to the sides.','Land softly with your feet shoulder-width apart, bending your knees to absorb the impact.','Repeat for the desired number of repetitions.']::text[], 'f9lVSSI'),
  ('db-3672', 'back and forth step', 'Other', 'Body Weight', 'cardiovascular system', ARRAY['quadriceps','hamstrings','glutes','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Step forward with your right foot, bending your knee and lowering your body into a lunge position.','Push off with your right foot and step back to the starting position.','Repeat the movement with your left foot, alternating legs with each step.','Continue stepping back and forth, maintaining a steady pace.','Repeat for the desired duration or number of repetitions.']::text[], 'fNGumX0'),
  ('db-1314', 'back extension on exercise ball', 'Back', 'Stability Ball', 'spine', ARRAY['glutes','hamstrings']::text[], ARRAY['Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface.','Position your hands behind your head or crossed over your chest.','Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'qLpO4vV'),
  ('db-3297', 'back lever', 'Back', 'Body Weight', 'upper back', ARRAY['biceps','forearms','core']::text[], ARRAY['Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.','Engage your core and pull your shoulder blades down and back.','Bend your knees and tuck them towards your chest.','Slowly lift your legs up, keeping them straight, until your body is parallel to the ground.','Hold this position for a few seconds, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'GaSzzuh'),
  ('db-1405', 'back pec stretch', 'Back', 'Body Weight', 'lats', ARRAY['shoulders','chest']::text[], ARRAY['Stand tall with your feet shoulder-width apart.','Extend your arms straight out in front of you, parallel to the ground.','Cross your arms in front of your body, with your right arm over your left arm.','Interlock your fingers and rotate your palms away from your body.','Slowly raise your arms up and away from your body, feeling a stretch in your back and chest.','Hold the stretch for 15-30 seconds, then release.','Repeat on the opposite side.']::text[], 'chfnQnM'),
  ('db-1473', 'backward jump', 'Legs', 'Body Weight', 'quads', ARRAY['hamstrings','glutes','calves']::text[], ARRAY['Stand with your feet shoulder-width apart.','Bend your knees slightly and jump backwards, pushing off with both feet.','Land softly on the balls of your feet, bending your knees to absorb the impact.','Repeat for the desired number of repetitions.']::text[], 'SaDOwk7'),
  ('db-0020', 'balance board', 'Legs', 'Body Weight', 'quads', ARRAY['calves','hamstrings','glutes']::text[], ARRAY['Place the balance board on a flat surface.','Step onto the balance board with one foot, ensuring it is centered.','Slowly shift your weight onto the foot on the balance board, keeping your core engaged.','Maintain your balance and stability as you hold the position for a desired amount of time.','Repeat the exercise with the other foot.']::text[], 'xAySMB0'),
  ('db-0968', 'band alternating biceps curl', 'Arms', 'Band', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the band with an underhand grip, palms facing up.','Keep your elbows close to your sides and slowly curl one arm up towards your shoulder, squeezing your biceps at the top.','Lower the arm back down to the starting position and repeat with the other arm.','Continue alternating arms for the desired number of repetitions.']::text[], '3omWx6P'),
  ('db-0969', 'band alternating v-up', 'Core', 'Band', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your legs straight and your arms extended overhead, holding the band.','Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.','As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other.','Repeat the movement, alternating the position of your legs with each repetition.','Continue for the desired number of repetitions.']::text[], 'ztAa1RK'),
  ('db-0970', 'band assisted pull-up', 'Back', 'Band', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Attach the band to a pull-up bar or sturdy anchor point.','Step onto the band and grip the bar with your palms facing away from you, hands slightly wider than shoulder-width apart.','Hang with your arms fully extended, keeping your core engaged and your shoulders down and back.','Pull your body up towards the bar by squeezing your shoulder blades together and driving your elbows down towards your hips.','Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'r1XNRYB'),
  ('db-0971', 'band assisted wheel rollerout', 'Core', 'Band', 'abs', ARRAY['lower back']::text[], ARRAY['Kneel on the floor and hold the handles of the band with both hands, palms facing down.','Place the band on the ground in front of you and position your hands shoulder-width apart.','Engage your core and slowly roll the wheel forward, extending your body as far as you can while maintaining control.','Pause for a moment at the furthest point, then slowly roll the wheel back towards your knees to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'zhF9lW4'),
  ('db-1254', 'band bench press', 'Chest', 'Band', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the band handles with an overhand grip, slightly wider than shoulder-width apart.','Extend your arms fully, pushing the bands away from your chest.','Slowly lower the bands back down to your chest, keeping your elbows at a 90-degree angle.','Repeat for the desired number of repetitions.']::text[], 'khlHMqs'),
  ('db-0980', 'band bent-over hip extension', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Attach the band to a sturdy anchor point at ankle height.','Stand facing away from the anchor point with your feet shoulder-width apart.','Step back to create tension in the band, keeping your knees slightly bent.','Hinge at the hips and lean forward, maintaining a neutral spine.','Extend your right leg straight back, squeezing your glutes at the top.','Lower your right leg back down and repeat with the left leg.','Continue alternating legs for the desired number of repetitions.']::text[], 'wSScovH'),
  ('db-0972', 'band bicycle crunch', 'Core', 'Band', 'abs', ARRAY['hip flexors','obliques']::text[], ARRAY['Lie flat on your back with your hands behind your head and your knees bent.','Lift your feet off the ground and bring your right knee towards your chest while simultaneously twisting your torso to bring your left elbow towards your right knee.','Straighten your right leg while bringing your left knee towards your chest and twisting your torso to bring your right elbow towards your left knee.','Continue alternating the twisting motion, as if you are pedaling a bicycle, while keeping your core engaged throughout the movement.','Repeat for the desired number of repetitions.']::text[], 'tZkGYZ9'),
  ('db-0974', 'band close-grip pulldown', 'Back', 'Band', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.','Stand facing the anchor point and grab the band with an underhand grip, hands shoulder-width apart.','Step back to create tension in the band, keeping your feet hip-width apart.','Engage your core and keep your back straight as you pull the band down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the band back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'DptumMx'),
  ('db-0975', 'band close-grip push-up', 'Arms', 'Band', 'triceps', ARRAY['chest','shoulders']::text[], ARRAY['Place a band around your upper arms, just above the elbows.','Assume a push-up position with your hands directly under your shoulders and your body in a straight line from head to heels.','Bend your elbows and lower your chest towards the ground, keeping your elbows close to your sides.','Push through your palms to extend your arms and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ufaxB52'),
  ('db-0976', 'band concentration curl', 'Arms', 'Band', 'biceps', ARRAY['forearms']::text[], ARRAY['Sit on a bench or chair with your legs spread apart and your feet flat on the ground.','Hold one end of the band in your hand and step on the other end with your foot on the same side.','Lean forward slightly and rest your elbow on the inside of your thigh, just above the knee.','With your palm facing up, slowly curl your hand towards your shoulder, keeping your upper arm stationary.','Pause for a moment at the top, then slowly lower your hand back down to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'kmVVAfu'),
  ('db-3117', 'band fixed back close grip pulldown', 'Back', 'Band', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Attach the band to a fixed point above you, such as a pull-up bar or sturdy beam.','Sit down on a bench or chair facing the band, with your feet flat on the ground and your knees bent.','Grasp the band with a close grip, palms facing towards you.','Keep your back straight and engage your core.','Pull the band down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, feeling the contraction in your lats.','Slowly release the band back to the starting position, maintaining control throughout the movement.','Repeat for the desired number of repetitions.']::text[], '4LoWllp'),
  ('db-3116', 'band fixed back underhand pulldown', 'Back', 'Band', 'lats', ARRAY['biceps','rhomboids','rear deltoids']::text[], ARRAY['Attach the band to a sturdy anchor point above your head.','Stand facing the anchor point with your feet shoulder-width apart.','Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.','Step back to create tension in the band, keeping your arms fully extended.','Engage your core and squeeze your shoulder blades together.','Pull the band down towards your chest, leading with your elbows.','Pause for a moment at the bottom of the movement, feeling the contraction in your lats.','Slowly release the tension in the band and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'ZH68exZ'),
  ('db-0977', 'band front lateral raise', 'Shoulders', 'Band', 'delts', ARRAY['traps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.','Keep your arms straight and lift the band up in front of you until your arms are parallel to the ground.','Pause for a moment at the top, then slowly lower the band back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'sTg7iys'),
  ('db-0978', 'band front raise', 'Shoulders', 'Band', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.','Keep your arms straight and slowly raise them forward until they are parallel to the ground.','Pause for a moment at the top, then slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'TFA88iB'),
  ('db-1408', 'band hip lift', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Lie on your back with your knees bent and feet flat on the ground.','Place a resistance band just above your knees.','Engage your glutes and core muscles.','Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top.','Pause for a moment at the top, then slowly lower your hips back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'E4R8Hz1'),
  ('db-0979', 'band horizontal pallof press', 'Core', 'Band', 'abs', ARRAY['obliques','glutes']::text[], ARRAY['Attach the band to a sturdy anchor point at waist height.','Stand perpendicular to the anchor point with your feet shoulder-width apart.','Grasp the band handle with both hands and step away from the anchor point to create tension in the band.','Bring your hands to your chest, keeping your elbows bent and close to your body.','Engage your core and maintain a stable stance.','Extend your arms straight out in front of you, pushing the band away from your body.','Hold the extended position for a few seconds, focusing on maintaining tension in your core.','Slowly bring your hands back to your chest, resisting the pull of the band.','Repeat for the desired number of repetitions.']::text[], '9pa4H5m'),
  ('db-0981', 'band jack knife sit-up', 'Core', 'Band', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your legs straight and your arms extended overhead, holding the band.','Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet.','Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'KCBKjma'),
  ('db-0983', 'band kneeling one arm pulldown', 'Back', 'Band', 'lats', ARRAY['biceps','rhomboids']::text[], ARRAY['Attach the band to a sturdy anchor point above your head.','Kneel down and hold the band with one hand, palm facing down.','Extend your arm fully overhead, keeping your elbow slightly bent.','Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage.','Pause for a moment at the bottom, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'pmnrOp0'),
  ('db-0985', 'band kneeling twisting crunch', 'Core', 'Band', 'abs', ARRAY['obliques']::text[], ARRAY['Attach the band to a sturdy anchor point at waist height.','Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides.','Engage your abs and slowly twist your torso to one side, bringing your hands towards your opposite hip.','Pause for a moment, then slowly return to the starting position.','Repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], '225x2Vd'),
  ('db-0984', 'band lying hip internal rotation', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Lie on your back with your legs straight and a resistance band looped around your feet.','Bend your knees and bring them towards your chest, keeping your feet together.','Slowly rotate your knees outwards, away from each other, while keeping your feet together.','Pause for a moment at the end of the rotation, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vIICElP'),
  ('db-1002', 'band lying straight leg raise', 'Core', 'Band', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your legs straight and your feet together.','Place the band around the arches of your feet and hold the ends of the band with your hands.','Engaging your abs, lift both legs off the ground until they are perpendicular to the floor.','Pause for a moment at the top, then slowly lower your legs back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'bbLR7fB'),
  ('db-0986', 'band one arm overhead biceps curl', 'Arms', 'Band', 'biceps', ARRAY['forearms','shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and place one end of the band under your foot.','Hold the other end of the band with your arm fully extended overhead, palm facing forward.','Keeping your upper arm stationary, curl your forearm towards your shoulder, squeezing your biceps.','Pause for a moment at the top, then slowly lower your forearm back to the starting position.','Repeat for the desired number of repetitions, then switch arms.']::text[], 'UNAB8ak'),
  ('db-0987', 'band one arm single leg split squat', 'Legs', 'Band', 'quads', ARRAY['glutes','hamstrings']::text[], ARRAY['Stand with your feet hip-width apart and place a resistance band around your ankles.','Extend one leg forward and rest the top of your foot on a bench or step behind you.','Hold onto a support with one hand for balance.','Bend your standing leg and lower your body down into a squat position, keeping your knee in line with your toes.','Push through your heel to return to the starting position.','Repeat for the desired number of repetitions, then switch legs.']::text[], 'arsYEd3'),
  ('db-0988', 'band one arm standing low row', 'Back', 'Band', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Attach the band to a stable anchor point at waist height.','Stand facing the anchor point with your feet shoulder-width apart.','Hold the band with one hand, palm facing inward, and step back to create tension in the band.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Pull the band towards your waist, squeezing your shoulder blades together.','Pause for a moment at the top of the movement, then slowly release the band back to the starting position.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'km0sQC0'),
  ('db-0989', 'band one arm twisting chest press', 'Chest', 'Band', 'pectorals', ARRAY['shoulders','triceps']::text[], ARRAY['Attach the band to a sturdy anchor point at chest height.','Stand with your side facing the anchor point and grab the band with one hand.','Step away from the anchor point to create tension in the band.','Position your feet shoulder-width apart and slightly bend your knees.','Bring your hand holding the band across your body, towards the opposite shoulder.','While maintaining tension in the band, push your hand forward and away from your body, extending your arm.','Slowly return to the starting position and repeat for the desired number of repetitions.','Switch sides and repeat the exercise with the other hand.']::text[], 'c16nYGA'),
  ('db-0990', 'band one arm twisting seated row', 'Back', 'Band', 'upper back', ARRAY['biceps','shoulders']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground and your back straight.','Hold the band with one hand and extend your arm fully in front of you.','Keeping your back straight, pull the band towards your body by bending your elbow and squeezing your shoulder blades together.','At the same time, twist your torso towards the side of the pulling arm.','Pause for a moment at the top, then slowly release the tension in the band and return to the starting position.','Repeat for the desired number of repetitions, then switch to the other arm.']::text[], 'DKBwJrL'),
  ('db-0991', 'band pull through', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Attach a resistance band to a sturdy anchor point at ground level.','Stand facing away from the anchor point with your feet shoulder-width apart.','Step forward to create tension in the band, keeping your knees slightly bent.','Hinge at the hips and push your glutes back, maintaining a slight bend in your knees.','Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.','Drive your hips forward and squeeze your glutes to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'VtTbiP3'),
  ('db-0992', 'band push sit-up', 'Core', 'Band', 'abs', ARRAY['shoulders','chest']::text[], ARRAY['Attach the band securely to a stable anchor point.','Lie flat on your back with your knees bent and feet flat on the ground.','Hold the band with both hands and extend your arms straight up towards the ceiling.','Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.','Pause for a moment at the top, then slowly lower your upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'zFzbBfL'),
  ('db-0993', 'band reverse fly', 'Shoulders', 'Band', 'delts', ARRAY['upper back','trapezius']::text[], ARRAY['Attach the band to a stationary object at chest height.','Stand with your feet shoulder-width apart and hold the band with both hands in front of you.','Keep your arms straight and lift them out to the sides until they are parallel to the ground.','Squeeze your shoulder blades together at the top of the movement.','Slowly lower your arms back to the starting position.','Repeat for the desired number of repetitions.']::text[], 'sTfvVsG'),
  ('db-0994', 'band reverse wrist curl', 'Arms', 'Band', 'forearms', ARRAY['forearms']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground.','Hold the band with an overhand grip, palms facing down, and wrap it around your fingers.','Rest your forearms on your thighs, with your wrists hanging off the edge.','Slowly curl your wrists upward, squeezing your forearms.','Pause for a moment at the top, then slowly lower your wrists back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Ezpnw9d'),
  ('db-0996', 'band seated hip internal rotation', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','quadriceps']::text[], ARRAY['Sit on a chair or bench with your back straight and feet flat on the ground.','Place a resistance band around your thighs, just above your knees.','Keep your knees bent at a 90-degree angle and your feet shoulder-width apart.','Engage your glutes and slowly rotate your knees outward, pushing against the resistance of the band.','Pause for a moment at the end of the movement, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], '9gbyYKk'),
  ('db-1011', 'band seated twist', 'Core', 'Band', 'abs', ARRAY['obliques']::text[], ARRAY['Sit on the ground with your legs extended in front of you and your back straight.','Wrap the band around your waist and hold the ends with both hands.','Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground.','Pause for a moment at the end of the twist, then slowly return to the starting position.','Repeat the twist to the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'S1JXDAG'),
  ('db-0997', 'band shoulder press', 'Shoulders', 'Band', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band under your feet.','Hold the band with your palms facing forward and raise your hands to shoulder height, elbows bent.','Press the band overhead, fully extending your arms.','Pause for a moment at the top, then slowly lower the band back to shoulder height.','Repeat for the desired number of repetitions.']::text[], 'peAeMR3'),
  ('db-1018', 'band shrug', 'Back', 'Band', 'traps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band under your feet, holding the ends with your hands.','Keep your arms straight and relaxed, and let the band hang in front of your thighs.','Engage your traps by shrugging your shoulders upward, lifting the band as high as possible.','Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'trmte8s'),
  ('db-0998', 'band side triceps extension', 'Arms', 'Band', 'triceps', ARRAY['shoulders']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down.','Extend your arms straight out to the sides, keeping them parallel to the ground.','Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still.','Pause for a moment, then slowly extend your arms back out to the starting position.','Repeat for the desired number of repetitions.']::text[], 'obe5LMq'),
  ('db-0999', 'band single leg calf raise', 'Legs', 'Band', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Stand with your feet hip-width apart and place the band around the ball of your left foot.','Hold onto a stable object for balance if needed.','Slowly raise your left heel off the ground, lifting your body weight onto the ball of your foot.','Pause for a moment at the top, then slowly lower your left heel back down to the starting position.','Repeat for the desired number of repetitions, then switch to the right leg.']::text[], '9JprnPh'),
  ('db-1000', 'band single leg reverse calf raise', 'Legs', 'Band', 'calves', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet hip-width apart and place the band around the ball of your foot.','Hold onto a stable object for balance.','Slowly raise your heel off the ground, lifting your body weight onto the ball of your foot.','Pause for a moment at the top, then slowly lower your heel back down to the starting position.','Repeat for the desired number of repetitions, then switch to the other leg.']::text[], 'QsSQWbf'),
  ('db-1001', 'band single leg split squat', 'Legs', 'Band', 'quads', ARRAY['glutes','hamstrings']::text[], ARRAY['Stand with your feet hip-width apart and place a resistance band around your ankles.','Take a big step forward with your right foot and a smaller step back with your left foot.','Bend your knees and lower your body until your right thigh is parallel to the ground, keeping your left knee slightly above the ground.','Push through your right heel to return to the starting position.','Repeat on the other side.']::text[], 'y8bYM8w'),
  ('db-1004', 'band squat', 'Legs', 'Band', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Stand with your feet shoulder-width apart, with the band placed just above your knees.','Keeping your chest up and core engaged, push your hips back and bend your knees to lower into a squat position.','Make sure your knees are tracking over your toes and your weight is in your heels.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'TUZLh71'),
  ('db-1003', 'band squat row', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','quadriceps','back']::text[], ARRAY['Attach the band to a sturdy anchor point at waist height.','Stand facing the anchor point with your feet shoulder-width apart.','Hold the band handles with your palms facing each other and your arms extended in front of you.','Bend your knees and lower into a squat position, keeping your back straight and chest lifted.','From the squat position, pull the band handles towards your body, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'w1NOByi'),
  ('db-1005', 'band standing crunch', 'Core', 'Band', 'abs', ARRAY['obliques']::text[], ARRAY['Attach the band to a sturdy anchor point at waist height.','Stand facing away from the anchor point with your feet shoulder-width apart.','Hold the band with both hands and bring it up to your chest, keeping your elbows bent and close to your body.','Engage your abs and slowly crunch forward, bringing your chest towards your knees.','Pause for a moment at the top of the crunch, then slowly return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Kzg30R7'),
  ('db-1022', 'band standing rear delt row', 'Shoulders', 'Band', 'delts', ARRAY['trapezius','rhomboids','biceps']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band under your feet.','Hold the band handles with your palms facing each other and your arms extended in front of you.','Bend your knees slightly and hinge forward at the hips, keeping your back straight.','Pull the band towards your chest, squeezing your shoulder blades together.','Pause for a moment at the top, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'tc5dYrf'),
  ('db-1007', 'band standing twisting crunch', 'Core', 'Band', 'abs', ARRAY['obliques']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band around your upper back, crossing it in front of your chest.','Hold the ends of the band with your hands, keeping your elbows bent and close to your sides.','Engage your abs and twist your torso to one side, bringing your elbow towards the opposite knee.','Pause for a moment, then return to the starting position.','Repeat on the other side.','Continue alternating sides for the desired number of repetitions.']::text[], 'euq4pwp'),
  ('db-1008', 'band step-up', 'Legs', 'Band', 'glutes', ARRAY['quadriceps','hamstrings','calves']::text[], ARRAY['Place a band around your thighs, just above your knees.','Stand facing a step or platform with your feet hip-width apart.','Step up onto the platform with your right foot, pushing through your heel.','Extend your left leg behind you, keeping it straight.','Lower your left foot back down to the ground.','Repeat with your left foot stepping up onto the platform.','Continue alternating legs for the desired number of repetitions.']::text[], 'd5bTEPV'),
  ('db-1009', 'band stiff leg deadlift', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band around your ankles.','Hold the band with both hands in front of your thighs, palms facing your body.','Keeping your back straight and your core engaged, hinge at the hips and slowly lower your upper body towards the ground.','As you lower, push your hips back and allow your knees to bend slightly.','Lower the band towards the ground, feeling a stretch in your hamstrings.','Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your upper body back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'kuMiR2T'),
  ('db-1023', 'band straight back stiff leg deadlift', 'Legs', 'Band', 'glutes', ARRAY['hamstrings','lower back']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band around your upper legs.','Hold the band with both hands in front of your thighs, palms facing your body.','Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground.','Feel the stretch in your hamstrings as you lower the band.','Engage your glutes and hamstrings to lift your body back up to the starting position.','Repeat for the desired number of repetitions.']::text[], 'lHeUULr'),
  ('db-1010', 'band straight leg deadlift', 'Back', 'Band', 'spine', ARRAY['hamstrings','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band around your feet.','Hold the band with both hands, palms facing your body, and keep your arms straight.','Engage your core and maintain a slight bend in your knees.','Slowly hinge forward at your hips, keeping your back straight and chest lifted.','Lower the band towards the ground while keeping your legs straight.','Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'KUaoUV8'),
  ('db-1012', 'band twisting overhead press', 'Shoulders', 'Band', 'delts', ARRAY['triceps','upper back']::text[], ARRAY['Stand with your feet shoulder-width apart and place the band under your feet.','Hold the band handles at shoulder height with your palms facing forward.','Engage your core and press the band overhead, fully extending your arms.','As you press, twist your torso to one side, keeping your hips stable.','Pause for a moment at the top, then return to the starting position.','Repeat the press and twist on the opposite side.','Continue alternating sides for the desired number of repetitions.']::text[], 'u4bAmKp'),
  ('db-1369', 'band two legs calf raise - (band under both legs) v. 2', 'Legs', 'Band', 'calves', ARRAY['ankles','feet']::text[], ARRAY['Stand with your feet shoulder-width apart and place a resistance band under both feet.','Hold the ends of the band with your hands for stability.','Raise your heels off the ground as high as possible, using your calves.','Pause for a moment at the top, then slowly lower your heels back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'jl6uxZV'),
  ('db-1013', 'band underhand pulldown', 'Back', 'Band', 'lats', ARRAY['biceps','forearms']::text[], ARRAY['Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.','Stand facing the anchor point with your feet shoulder-width apart.','Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.','Extend your arms fully overhead, keeping your elbows slightly bent.','Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together.','Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'k6tUeqS'),
  ('db-1014', 'band v-up', 'Core', 'Band', 'abs', ARRAY['hip flexors']::text[], ARRAY['Lie flat on your back with your legs straight and your arms extended overhead, holding the band.','Engaging your abs, lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.','Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'H6ETwO9'),
  ('db-1015', 'band vertical pallof press', 'Core', 'Band', 'abs', ARRAY['obliques','glutes']::text[], ARRAY['Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height.','Hold the band with both hands and step away from the anchor point, creating tension in the band.','Position yourself perpendicular to the anchor point, with your side facing the band.','Extend your arms straight out in front of you, keeping your hands at chest height.','Engage your core and press the band away from your chest, fully extending your arms.','Hold the position for a few seconds, then slowly bring the band back towards your chest.','Repeat for the desired number of repetitions, then switch sides.']::text[], 'G7PXMlT'),
  ('db-1016', 'band wrist curl', 'Arms', 'Band', 'forearms', ARRAY['biceps','triceps']::text[], ARRAY['Sit on a bench or chair with your feet flat on the ground.','Hold the band with both hands, palms facing up, and rest your forearms on your thighs.','Slowly curl your wrists upward, squeezing your forearms.','Pause for a moment at the top, then slowly lower your wrists back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'vUTfFHw'),
  ('db-1017', 'band y-raise', 'Shoulders', 'Band', 'delts', ARRAY['traps','rhomboids']::text[], ARRAY['Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing inwards.','Keep your arms straight and lift them up and out to the sides, forming a ''Y'' shape with your body.','Squeeze your shoulder blades together at the top of the movement.','Slowly lower your arms back down to the starting position.','Repeat for the desired number of repetitions.']::text[], 'aHDy5O5'),
  ('db-0023', 'barbell alternate biceps curl', 'Arms', 'Barbell', 'biceps', ARRAY['forearms']::text[], ARRAY['Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward.','Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.','Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level.','Hold the contracted position for a brief pause as you squeeze your biceps.','Inhale as you slowly begin to lower the barbells back to the starting position.','Repeat for the desired number of repetitions, alternating arms.']::text[], 'Yza7XrQ'),
  ('db-0024', 'barbell bench front squat', 'Legs', 'Barbell', 'quads', ARRAY['hamstrings','glutes','calves']::text[], ARRAY['Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone.','Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground.','Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up.','Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'Y7YcmIJ'),
  ('db-0025', 'barbell bench press', 'Chest', 'Barbell', 'pectorals', ARRAY['triceps','shoulders']::text[], ARRAY['Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.','Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.','Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.','Lower the barbell slowly towards your chest, keeping your elbows tucked in.','Pause for a moment when the barbell touches your chest.','Push the barbell back up to the starting position by extending your arms.','Repeat for the desired number of repetitions.']::text[], 'EIeI8Vf'),
  ('db-0026', 'barbell bench squat', 'Legs', 'Barbell', 'quads', ARRAY['glutes','hamstrings','calves']::text[], ARRAY['Set up a barbell on a squat rack at chest height.','Stand facing away from the rack, with your feet shoulder-width apart.','Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.','Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.','Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart.','Lower your body down into a squat, keeping your knees in line with your toes.','Pause for a moment at the bottom, then push through your heels to return to the starting position.','Repeat for the desired number of repetitions.']::text[], 'W9pFVv1')
